/**
 * Registers the app's custom URL scheme on MainActivity.
 *
 * Sign-in can't happen inside the WebView — Google rejects OAuth in embedded
 * browsers — so the app opens the system browser, the backend finishes the
 * exchange, and then redirects to `com.subhm2004.flappydusk://auth?token=…` to
 * hand the session back. Android only routes that URL to us if MainActivity
 * declares a matching intent-filter, and Capacitor 6's template doesn't ship
 * one.
 *
 * android/ is regenerated by `npx cap add android` on every CI run, so this
 * runs every build rather than being committed.
 */
import { readFileSync, writeFileSync } from 'node:fs';

const MANIFEST = 'android/app/src/main/AndroidManifest.xml';

const FILTER = `
            <intent-filter>
                <action android:name="android.intent.action.VIEW" />
                <category android:name="android.intent.category.DEFAULT" />
                <category android:name="android.intent.category.BROWSABLE" />
                <data android:scheme="@string/custom_url_scheme" />
            </intent-filter>
`;

const manifest = readFileSync(MANIFEST, 'utf8');

if (manifest.includes('android.intent.action.VIEW')) {
  console.log('deep link: already registered, nothing to do');
  process.exit(0);
}

// Anchor on the LAUNCHER filter's closing tag — the only intent-filter in the
// template — and add ours right after it, still inside <activity>.
const anchor = `                <category android:name="android.intent.category.LAUNCHER" />
            </intent-filter>
`;

if (!manifest.includes(anchor)) {
  console.error(
    `deep link: could not find the launcher intent-filter in ${MANIFEST}.\n` +
      'The Capacitor template changed — update this script.',
  );
  process.exit(1);
}

writeFileSync(MANIFEST, manifest.replace(anchor, anchor + FILTER));
console.log('deep link: registered com.subhm2004.flappydusk:// on MainActivity');
